const amthanh =
	'';
let prev = 0;
let count = 1;
const base64Audio = amthanh; // Thay thế bằng chuỗi base64 của âm thanh của bạn
const audio = new Audio(`data:audio/mp3;base64,${base64Audio}`);
setInterval(function () {
	let c = document.querySelector(
		'.x1vvvo52.xw23nyj.x63nzvj.x1heor9g.xuxw1ft.x6ikm8r.x10wlt62.xlyipyv.x1h4wwuj.x1pd3egz.xeuugli'
	);
	let newC = Number(c.innerHTML) > 0 ? Number(c.innerHTML) : 0;
	if (newC > prev && newC >= 1) {
		document.title = `Có ${newC} tin nhắn`;
		prev = newC;
		if (count === 1) {
			audio.play();
			count = count + 100;
		}
	} else if (prev > newC) {
		prev = newC;
	} else {
		document.title = 'Meta';
		count = 1;
		prev = newC;
	}
	if (newC > 0) document.title = `Có ${newC} tin nhắn`;
}, 1000);

setInterval(function () {
	console.clear();
}, 160000);
